// quoteStatusBadgeClass returns a Tailwind badge class for a QuoteStatus.
func quoteStatusBadgeClass(s models.QuoteStatus) string {
	switch s {
	case models.QuoteStatusDraft:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted"
	case models.QuoteStatusSent:
		return "inline-flex items-center rounded-full bg-info-soft px-2.5 py-0.5 text-small font-medium text-info-hover"
	case models.QuoteStatusAccepted:
		return "inline-flex items-center rounded-full bg-success-soft px-2.5 py-0.5 text-small font-medium text-success-hover"
	case models.QuoteStatusRejected:
		return "inline-flex items-center rounded-full bg-danger-soft px-2.5 py-0.5 text-small font-medium text-danger-hover"
	case models.QuoteStatusConverted:
		return "inline-flex items-center rounded-full bg-primary-soft px-2.5 py-0.5 text-small font-medium text-primary"
	case models.QuoteStatusCancelled:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted2"
	default:
		return "inline-flex items-center rounded-full bg-muted-soft px-2.5 py-0.5 text-small font-medium text-text-muted"
	}
}

